function normalizeAiModelProfiles(
  profiles?: Partial<Record<AiModelProfileKey, AiModelProfileRecord>> | null,
): Record<AiModelProfileKey, AiModelProfileRecord> {
  return AI_MODEL_PROFILE_ORDER.reduce((acc, key) => {
    const incoming = profiles?.[key];
    const base = AI_MODEL_PROFILE_DEFAULTS[key];
    const next = {
      ...base,
      ...(incoming || {}),
      provider: 'openai_compatible' as AiProvider,
      capability: incoming?.capability || base.capability,
    };
    next.isLocal = isLocalAiBaseUrl(next.baseUrl);
    acc[key] = next;
    return acc;
  }, {} as Record<AiModelProfileKey, AiModelProfileRecord>);
}

function resolveAiConfigPresetKey(draft: {
  aiProvider?: AiProvider | string | null;
  aiBaseUrl?: string | null;
  aiModel?: string | null;
}): AiConfigPresetKey {
  const provider = String(draft.aiProvider || '').trim();
  if (provider === AI_CONFIG_PRESETS.mock.provider) return 'custom';
  if (provider === AI_CONFIG_PRESETS.openclaw.provider) return 'openclaw';
  const baseUrl = normalizeAiBaseUrl(draft.aiBaseUrl);
  const model = String(draft.aiModel || '').trim();
  const matchedPreset = AI_CONFIG_PRESET_ORDER.find((presetKey) => {
    if (presetKey === 'custom' || presetKey === 'mock' || presetKey === 'openclaw') return false;
    const preset = AI_CONFIG_PRESETS[presetKey];
    return provider === preset.provider
      && baseUrl === normalizeAiBaseUrl(preset.baseUrl)
      && model === preset.model;
  });
  return matchedPreset || 'custom';
}

function aiModelDisplayLabel(provider?: AiProvider | string | null, model?: string | null, providerLabel?: string | null) {
  // 顾源源 5/26 真用反馈: 主仓 db 真出现 ai_provider='openclaw' 但 ai_provider_label='豆包 Seed 2.0 Pro' 真矛盾,
  // 真用户看到"豆包"但后端真走 OpenClaw GPT-5.4. 真"显示 X 用 Y" 真信任崩.
  //
  // 真修法: 真按 provider (路由真值) 真硬编算 label, 真**忽略 db.providerLabel** (它真可能 stale).
  // db.providerLabel 真降级成 advisory (用户自定义 alias), 真不再作为权威显示源.
  // → 真用户永远看到的 = 真实路由, 真切模型不再撞"label 跟 provider 真不一致".
  const providerValue = String(provider || '').trim() as AiProvider | '';
  const modelValue = String(model || '').trim();
  const labelValue = String(providerLabel || '').trim();
  // 真按 provider 真路由值优先返 hardcoded display name
  if (providerValue === 'mock') return providerDisplayNames.mock;
  if (providerValue === 'openclaw') return providerDisplayNames.openclaw;
  if (providerValue === 'doubao') {
    return (!modelValue || modelValue === providerDefaultModels.doubao)
      ? providerDisplayNames.doubao
      : `${providerDisplayNames.doubao} · ${modelValue}`;
  }
  if (providerValue === 'qwen') {
    return (!modelValue || modelValue === providerDefaultModels.qwen)
      ? providerDisplayNames.qwen
      : `${providerDisplayNames.qwen} · ${modelValue}`;
  }
  // openai_compatible 真没固定路由, label 真用 model 优先 (provider 真自定义) — 真 fallback labelValue 作 alias
  if (providerValue === 'openai_compatible') {
    return modelValue || labelValue || providerDisplayNames.openai_compatible;
  }
  // 真未知 provider — fallback label 或 model
  if (labelValue) return labelValue;
  if (modelValue) return modelValue;
  return providerValue && providerValue in providerDisplayNames
    ? providerDisplayNames[providerValue as keyof typeof providerDisplayNames]
    : 'AI';
}

function aiRouteLabel(provider?: AiProvider | string | null, model?: string | null, providerLabel?: string | null) {
  const label = aiModelDisplayLabel(provider, model, providerLabel);
  return label === 'AI' ? 'AI' : `AI · ${label}`;
}

const CLOUD_API_URL_PREFIX = 'http://';

function cloudApiHostValue(rawUrl?: string | null) {
  return String(rawUrl || '')
    .trim()
    .replace(/^https?:\/\//i, '')
    .replace(/\/.*$/, '');
}

function cloudApiUrlFromHost(rawHost?: string | null) {
  const host = cloudApiHostValue(rawHost);
  return host ? `${CLOUD_API_URL_PREFIX}${host}` : '';
}

type HealthAiSnapshot = HealthResponse['ai'] | null | undefined;

function isRealAiConfigured(ai: HealthAiSnapshot) {
  return Boolean(
    ai
    && ai.provider
    && ai.provider !== 'mock'
    && ai.ready,
  );
}

function getWorkspaceAiUnavailableReason(ai: HealthAiSnapshot) {
  if (!ai?.provider) return '正在读取大模型配置，请稍后再试。';
  if (ai.provider === 'mock') return '还没有配置真实大模型。请先到系统设置的 AI 与云端填写 Base URL、模型名和 API Key。';
  const label = aiModelDisplayLabel(ai.provider, ai.model, ai.providerLabel);
  if (!ai.ready) return ai.detail || `${label} 还没有配置完成，暂时不能生成正式回答。`;
  return '';
}

const COLLAB_REPO_PATH_STORAGE_KEY = 'yiyu-collab-repo-path';
const EVENT_LINE_PROJECT_FILTER_STORAGE_KEY = 'yiyu-event-line-project-filter';
const COLLAB_PRIMARY_REPO_NAME = 'yiyu-thinktank-workbench';
const COLLAB_LEGACY_REPO_NAME = 'yiyu-thinktank-workbench-main-sync';
const COLLAB_LOCAL_LEGACY_REPO_NAMES = new Set([
  COLLAB_LEGACY_REPO_NAME,
  'yiyu-thinktank-workbench-2.0-collab',
]);
const COLLAB_VISIBLE_WORKSPACE_SEGMENT = '/openclaw/workspace';
const COLLAB_HIDDEN_WORKSPACE_SEGMENT = '/.openclaw/workspace';

function normalizeCollabRepoPathValue(rawPath: string) {
  return rawPath.replace(/[\\/]+$/, '');
}

function normalizeInitialCollabRepoPath(storedPath: string | null) {
  if (!storedPath) return null;
  let normalized = normalizeCollabRepoPathValue(storedPath);
  if (normalized.includes(COLLAB_HIDDEN_WORKSPACE_SEGMENT)) {
    normalized = normalized.replace(COLLAB_HIDDEN_WORKSPACE_SEGMENT, COLLAB_VISIBLE_WORKSPACE_SEGMENT);
  }
  const repoName = normalized.split('/').filter(Boolean).at(-1);
  if (repoName && COLLAB_LOCAL_LEGACY_REPO_NAMES.has(repoName)) {
    return null;
  }
  if (normalized.endsWith(`/${COLLAB_LEGACY_REPO_NAME}`)) {
    return normalized.slice(0, -COLLAB_LEGACY_REPO_NAME.length) + COLLAB_PRIMARY_REPO_NAME;
  }
  if (normalized.endsWith('/workspace')) {
    return `${normalized}/${COLLAB_PRIMARY_REPO_NAME}`;
  }
  return normalized;
}

