  const [maintenanceModeStatus, setMaintenanceModeStatus] = useState<MaintenanceModeStatus | null>(null);
  const [maintenanceModeError, setMaintenanceModeError] = useState<string | null>(null);
  const [isMaintenanceModeLoading, setIsMaintenanceModeLoading] = useState(false);
  const [maintenanceModeBusyAction, setMaintenanceModeBusyAction] = useState<'enter' | 'exit' | null>(null);
  const [taskViewMode, setTaskViewMode] = useState<TaskViewMode>('calendar');
  // 「组织计划」面板（侧栏 viewMap.plan_workshop）跟任务编辑器在不同 React 子树里：
  // 任务模态框只在 TasksView 内挂载。这里用一次性脉冲把"打开任务详情 / 生成任务"请求
  // 跨越 viewMap 边界传给 TasksView，让它切到 tasks 路由后再触发 openTaskEditor。
  const [pendingPlanItemAction, setPendingPlanItemAction] = useState<
    | { kind: 'open-task'; task: Task }
    | { kind: 'generate-from-plan-item'; planItem: { id: string; title?: string; statement?: string }; scopeName: string }
    | null
  >(null);
  const taskViewportRef = useRef<HTMLDivElement | null>(null);
  const reviewViewportRef = useRef<HTMLDivElement | null>(null);
    const [taskSelectedDay, setTaskSelectedDay] = useState(initialTodayState.selectedDay);
    const [taskCalendarDisplayMode, setTaskCalendarDisplayMode] = useState<'month' | 'week'>('month');
    const [taskSelectedDate, setTaskSelectedDate] = useState(() => new Date(initialTodayState.calendarDate.getFullYear(), initialTodayState.calendarDate.getMonth(), initialTodayState.selectedDay));
  const [taskCalendarDate, setTaskCalendarDate] = useState(initialTodayState.calendarDate);
  const [taskCalendarDetailOpen, setTaskCalendarDetailOpen] = useState(false);
  const [expandedTaskIds, setExpandedTaskIds] = useState<string[]>([]);
  const taskCalendarMonthLabel = `${taskCalendarDate.getFullYear()}-${String(taskCalendarDate.getMonth() + 1).padStart(2, '0')}`;
  const [clientOverlayMode, setClientOverlayMode] = useState<ClientOverlayMode>(null);
  // P9：客户工作台内嵌文档编辑器（点钢笔按钮直接进入此模式，主区切到 doc editor，不弹窗）。
  // null = 普通 chat / 工作台视图；非 null = 全屏 doc editor 模式。
  // enableDraftPersist:钢笔新建空白文档时为 true → debounce 写 localStorage,关编辑器/闪退能找回。
  // 其他 entry(从 AI 答案带内容、打开已有文档)= undefined/false,避免覆盖已有文档草稿。
  const [clientWorkspaceInlineEditor, setClientWorkspaceInlineEditor] = useState<{
    clientId: string;
    title: string;
    content: string;
    titleEdited: boolean;
    sourceDocumentId?: string;
    enableDraftPersist?: boolean;
    recoveredFromDraft?: boolean;
  } | null>(null);
  // P12：inline editor 全屏开关。fullscreen=true 时 fixed inset-0 z-[1000] 盖住整个 Electron window；
  // false 时 absolute inset-0 z-30 只盖中间主区（左侧栏 + 右工具栏可见）。
  const [isInlineEditorFullscreen, setIsInlineEditorFullscreen] = useState(false);
  // 用户在 inline editor 模式下点右侧文件 ← 箭头 → bump 这个 key,编辑器 useEffect 会自动弹出 AI popover。
  // counter 模式而不是 boolean,避免"开了又关用户又点"时第二次不触发(boolean 要 reset)。
  const [inlineEditorOpenAiPromptKey, setInlineEditorOpenAiPromptKey] = useState(0);

  // 用户收藏的快捷工具 key 列表。
  // 工具页里点 ☆ 加入收藏，会持久化到 localStorage，并在快捷工具区下方追加显示。
  // 与原有 5 个固定按钮并存——固定按钮是产品默认入口，收藏是用户主导的额外快捷。
  const [favoriteWorkspaceTools, setFavoriteWorkspaceTools] = useState<string[]>(() => {
    if (typeof window === 'undefined') return [];
    try {
      const raw = window.localStorage.getItem('yiyu.workspace.favoriteTools');
      const parsed = raw ? JSON.parse(raw) : [];
      const list = Array.isArray(parsed)
        ? parsed.filter((item): item is string => typeof item === 'string')
        : [];
      // 顾源源 5/26: 真 migration — 旧 key 'import_folder' / 'import_files' 真已合并为 'import'.
      // 真自动迁移 (用户旧收藏不丢, 真去重) + 真清除 registry 已不存在的 invalid key.
      // 真原 bug: 旧 key 真占 favorite slot 但 UI 真过滤掉 → 用户感觉"加 1 个占 2 位".
      const KNOWN_TOOL_KEYS = new Set([
        'import', 'fill_template', 'text_doc', 'link_material', 'smart_import',
      ]);
      const migrated: string[] = [];
      let hasLegacyImport = false;
      for (const key of list) {
        if (key === 'import_folder' || key === 'import_files') {
          hasLegacyImport = true;
          continue;
        }
        if (KNOWN_TOOL_KEYS.has(key) && !migrated.includes(key)) {
          migrated.push(key);
        }
      }
      if (hasLegacyImport && !migrated.includes('import')) {
        migrated.unshift('import');
      }
      return migrated;
    } catch {
      return [];
    }
  });
  useEffect(() => {
    try {
      window.localStorage.setItem('yiyu.workspace.favoriteTools', JSON.stringify(favoriteWorkspaceTools));
    } catch {
      // localStorage 写失败（隐私模式 / 配额满）不影响主流程
    }
  }, [favoriteWorkspaceTools]);

  // inline editor 草稿 debounce 写入 localStorage —— 防丢失底线(Tier 1)
  // 只在钢笔新建 entry(enableDraftPersist=true)启用,避免覆盖来自已有文档的 entry。
  useEffect(() => {
    if (!clientWorkspaceInlineEditor?.enableDraftPersist) return;
    const { clientId, content, title } = clientWorkspaceInlineEditor;
    // 全空就直接清,避免空草稿堆在 localStorage
    if (!content.trim() && !title.trim()) {
      clearInlineEditorDraft(clientId);
      return;
    }
    const timer = window.setTimeout(() => {
      writeInlineEditorDraft(clientId, content, title);
    }, 1000);
    return () => window.clearTimeout(timer);
  }, [
    clientWorkspaceInlineEditor?.clientId,
    clientWorkspaceInlineEditor?.content,
    clientWorkspaceInlineEditor?.title,
    clientWorkspaceInlineEditor?.enableDraftPersist,
  ]);

  // 快捷工具区最多 5 个，超出时拒绝并 flash 提示。
  // flash 函数在文件下方才声明（line ~7399），这里用 ref 转一手避免"used before declaration"。
  const flashRef = useRef<((type: 'success' | 'error' | 'info', text: string) => void) | null>(null);
  // 多个 modal 的 backdrop 点击关闭共享 ref —— 这些 modal 互斥渲染.
  // 用于区分"真点击 backdrop"和"从 modal 内部 input/textarea 拖选鼠标滑出".
  // 详见 src/renderer/lib/useBackdropClickClose.ts
  const backdropMouseDownRef = useRef(false);
  const toggleFavoriteWorkspaceTool = useCallback((toolKey: string) => {
    const FAVORITE_LIMIT = 5;
    setFavoriteWorkspaceTools((prev) => {
      if (prev.includes(toolKey)) {
        return prev.filter((key) => key !== toolKey);
      }
      if (prev.length >= FAVORITE_LIMIT) {
        flashRef.current?.('info', `快捷工具区最多 ${FAVORITE_LIMIT} 个，请先移除一个再添加`);
        return prev;
      }
      return [...prev, toolKey];
    });
  }, []);
  const [clientEditorModalState, setClientEditorModalState] = useState<ClientEditorModalState>(() => ({
    open: false,
    editingClientId: null,
    requestId: 'client-editor-initial',
    initialDraft: createEmptyClientEditorDraft(),
  }));
  const clientEditorModalStateRef = useRef(clientEditorModalState);
  const [clientWorkspaceSurfaceModeRequest, setClientWorkspaceSurfaceModeRequest] = useState<{
    clientId: string;
    mode: 'setup' | 'workspace';
    requestId: string;
  } | null>(null);
  const [workspaceSelectedMeetingId, setWorkspaceSelectedMeetingId] = useState('');
  const [workspaceMeetingTranscript, setWorkspaceMeetingTranscript] = useState('');
  const [workspaceMeetingNotes, setWorkspaceMeetingNotes] = useState('');

  const [authState, setAuthState] = useState<AuthState>(DEFAULT_LOCAL_AUTH_STATE);
  const [departmentOptions, setDepartmentOptions] = useState<DepartmentOption[]>([]);
  const [employeeReviews, setEmployeeReviews] = useState<EmployeeRecord[]>([]);
  const [settingsState, setSettingsState] = useState<AppSettings | null>(null);
  const [taskSettingsState, setTaskSettingsState] = useState<TaskSettings | null>(null);
  const [orgModelState, setOrgModelState] = useState<OrgModelSettings>(EMPTY_ORG_MODEL_SETTINGS);
  const [agentWorklogs, setAgentWorklogs] = useState<AgentWorklog[]>([]);
  const [agentWeeklyDigests, setAgentWeeklyDigests] = useState<AgentWeeklyDigest[]>([]);
  const [agentWeeklyPlans, setAgentWeeklyPlans] = useState<AgentWeeklyPlan[]>([]);
  const [operators, setOperators] = useState<Operator[]>([]);
  const [health, setHealth] = useState<HealthResponse | null>(null);
  const [desktopAppInfo, setDesktopAppInfo] = useState<DesktopAppInfo | null>(null);
  const [hasOfficialPush, setHasOfficialPush] = useState(() => (
    typeof window !== 'undefined' ? Boolean(window[UPDATE_STATE_KEY]?.officialPush) : false
  ));
  const [officialPushToast, setOfficialPushToast] = useState<OfficialPushUpdatePayload | null>(() => (
    typeof window !== 'undefined' ? window[UPDATE_STATE_KEY]?.officialPush ?? null : null
  ));
  const canUseCollabSync = Boolean(desktopAppInfo && desktopAppInfo.platform !== 'browser');
  const isMaintenanceModeActive = Boolean(maintenanceModeStatus?.active);
  const canShowCollabSync = canUseCollabSync && isMaintenanceModeActive;
  const [workspaceThreadPreference, setWorkspaceThreadPreference] = useState<WorkspaceThreadPreference>(
    initialNavigationStateRef.current.workspaceThreadPreference,
  );
  const [workspaceSourceIntegrity, setWorkspaceSourceIntegrity] = useState<SourceIntegrityReport | null>(null);
  const [backendCompatibilityError, setBackendCompatibilityError] = useState<string | null>(null);
  const [isImportSubmitting, setIsImportSubmitting] = useState(false);
  const [latestImportFeedback, setLatestImportFeedback] = useState<ImportFeedback | null>(null);
  const [activeWorkingDocuments, setActiveWorkingDocuments] = useState<ActiveWorkingDocument[]>([]);
  const activeWorkingDocumentsClientRef = useRef('');
  const importProgressHoldUntilRef = useRef<number>(0);
  const [settingsSection, setSettingsSection] = useState<SettingsSectionKey>(initialNavigationStateRef.current.settingsSection);
  const [evidenceMode, setEvidenceMode] = useState<EvidenceMode | null>(initialNavigationStateRef.current.evidenceMode);
  const [evidenceTaskId, setEvidenceTaskId] = useState<string | null>(initialNavigationStateRef.current.evidenceTaskId);
  const [evidenceClientId, setEvidenceClientId] = useState<string | null>(initialNavigationStateRef.current.evidenceClientId);
  const [settingsSectionLoaded, setSettingsSectionLoaded] = useState<Record<SettingsSectionKey, boolean>>({
    overview: true,
    account: false,
    tasks: true,
    client_workspace: false,
    topics: false,
    handbook: false,
    system_admin: false,
    org_overview: false,
    org_departments: false,
      org_people: false,
      org_rules: false,
      system_logs: false,
      about: false,
    });
  const [logs, setLogs] = useState<
    Array<{
      id: string;
      actorName: string;
      action: string;
      entityType: string;
      entityId: string;
      detail: Record<string, unknown>;
      createdAt: string;
    }>
  >([]);
  const [clientWorkspaceSettingsState, setClientWorkspaceSettingsState] = useState<ClientWorkspaceSettings>(DEFAULT_CLIENT_WORKSPACE_SETTINGS);
  const [topicsSettingsState, setTopicsSettingsState] = useState<TopicsSettings>(DEFAULT_TOPICS_SETTINGS);
  const [handbookSettingsState, setHandbookSettingsState] = useState<HandbookSettings>(DEFAULT_HANDBOOK_SETTINGS);
  const [systemAdminSettingsState, setSystemAdminSettingsState] = useState<SystemAdminSettings>(DEFAULT_SYSTEM_ADMIN_SETTINGS);
  const [orgMembershipState, setOrgMembershipState] = useState<OrgMembershipSummary>(DEFAULT_ORG_MEMBERSHIP_SUMMARY);
  const [orgAdminClaimStatus, setOrgAdminClaimStatus] = useState<OrgAdminClaimStatus>(DEFAULT_ORG_ADMIN_CLAIM_STATUS);
  const [orgAdminClaimBusy, setOrgAdminClaimBusy] = useState(false);
  const [orgFeishuIntegrationState, setOrgFeishuIntegrationState] = useState<OrgFeishuIntegration>(DEFAULT_ORG_FEISHU_INTEGRATION);
  const [feishuDeliveryProfileState, setFeishuDeliveryProfileState] = useState<FeishuDeliveryProfile>(DEFAULT_FEISHU_DELIVERY_PROFILE);
  const [feishuMemberAuthorizationState, setFeishuMemberAuthorizationState] = useState<FeishuMemberAuthorization>(DEFAULT_FEISHU_MEMBER_AUTHORIZATION);
  const [feishuAuthorizationBusyAction, setFeishuAuthorizationBusyAction] = useState<'idle' | 'starting' | 'refreshing' | 'clearing'>('idle');
  const [feishuAuthorizationFlowState, setFeishuAuthorizationFlowState] = useState<FeishuAuthorizationFlowState | null>(null);
  const [isSavingOrgFeishuIntegration, setIsSavingOrgFeishuIntegration] = useState(false);
  const [isSavingFeishuDeliveryProfile, setIsSavingFeishuDeliveryProfile] = useState(false);

  const [clients, setClients] = useState<ClientSummary[]>([]);
  // 全局冷冻订阅 — 本地 hiddenClientIds Set 是 clients[].isFrozen 的镜像
  // 当 clients refetch 后,把 isFrozen=true 的客户同步进 Set;反之则移除
  // 这样所有依赖 isClientHidden() 的代码(下拉/列表)立刻反映后端真实状态
  const [hiddenClientsVersion, setHiddenClientsVersion] = useState(0);
  useEffect(() => {
    const listener = () => setHiddenClientsVersion((v) => v + 1);
    hiddenClientsListeners.add(listener);
    return () => {
      hiddenClientsListeners.delete(listener);
    };
  }, []);
  // 把 clients[].isFrozen 同步进本地 Set(后端是 SOT)
  // 注意:这个 effect 之前有一个 issue,当 clients 引用变(refetch)时会触发 listener,
  //       而 listener setHiddenClientsVersion 让 dataCenterClients useMemo 重算 → 新引用,
  //       下游 effect 看到新 deps 又跑 → 形成连锁。
  // 防御:用 ref 缓存"上次同步过的"clients 引用,引用相同就跳过整个 effect 体
  const lastSyncedClientsRef = useRef<ClientSummary[] | null>(null);
  useEffect(() => {
    if (lastSyncedClientsRef.current === clients) return;
    lastSyncedClientsRef.current = clients;
    let dirty = false;
    for (const client of clients) {
      const backendFrozen = Boolean(client.isFrozen);
      const localHidden = hiddenClientIds.has(client.id);
      if (backendFrozen !== localHidden) {
        if (backendFrozen) hiddenClientIds.add(client.id);
        else hiddenClientIds.delete(client.id);
        dirty = true;
      }
    }
    if (dirty) {
      _persistHiddenSet(hiddenClientIds);
      for (const listener of hiddenClientsListeners) listener();
    }
  }, [clients]);
  // P7：参与数据中心的 client 子集（隐藏掉勾了"仅工作台"的项目，例如"新思考"/"顾源源文章"
  // 这种资料筐）。客户工作台、项目编辑 modal 继续用全量 clients；战略陪伴 / 咨询 / 情报 /
  // 任务的客户 selector 使用这个 memo，避免把资料筐客户暴露给数据中心计算视图。
  // 增强:用户主动隐藏(isClientHidden)的项目也从这里过滤掉,实现"全局冷冻";
  //       但当前正在浏览的 currentClientId 即使被隐藏也保留(避免切换中上下文丢失)
  const [currentClientId, setCurrentClientId] = useState<string>('');
  const dataCenterClients = useMemo(() => {
    void hiddenClientsVersion;
    // 冷冻的项目对所有非工作台 view 不可见 — 战略陪伴/资讯/计划/任务下拉统统过滤
    // 例外:当前正在浏览的 currentClientId 即使被冷冻也保留(避免切换 view 时上下文丢失,
    //       以及防止某些 effect 在 dataCenterClients 突然不含 currentClient 时陷入死循环)
    return clients.filter((c) => {
      if (c.isDataCenterIncluded === false) return false;
      if (isClientHidden(c.id) && c.id !== currentClientId) return false;
      return true;
    });
  }, [clients, hiddenClientsVersion, currentClientId]);
  const [workspaceClientUiState, dispatchWorkspaceClientUi] = useReducer(
    workspaceClientUiReducer,
    initialWorkspaceClientUiState,
  );
  const workspaceComposerDraftByClient = workspaceClientUiState.composerDraftByClient;
  const workspaceActiveRunByClient = workspaceClientUiState.activeRunByClient;
  const workspacePendingQuestionByClient = workspaceClientUiState.pendingQuestionByClient;
  const workspaceOptimisticMessagesByThread = workspaceClientUiState.optimisticMessagesByThread;
  const workspaceComposerDraftRef = useRef<Record<string, string>>({});
  const workspaceStartMessageAbortControllerRef = useRef<AbortController | null>(null);
  const workspaceLastClientResetRef = useRef<string | null>(null);
  const workspaceComposerFocusRef = useRef<{
    key: string;
    focused: boolean;
    selectionStart: number | null;
    selectionEnd: number | null;
    updatedAt: number;
  }>({
    key: '',
    focused: false,
    selectionStart: null,
    selectionEnd: null,
    updatedAt: 0,
  });
  const workspaceComposerCompositionRef = useRef(false);
  const workspaceSelectedThreadId = currentClientId
    ? workspaceClientUiState.selectedThreadIdByClient[currentClientId] || null
    : null;
  const setWorkspaceSelectedThreadId = useCallback((threadId: string | null) => {
    if (!currentClientId) return;
    dispatchWorkspaceClientUi({ type: 'setSelectedThreadId', clientId: currentClientId, threadId });
  }, [currentClientId]);
  const [workspace, setWorkspace] = useState<ClientWorkspace | null>(null);
  const [workspacePageContext, setWorkspacePageContext] = useState<PageContextPack | null>(null);
  const [workspacePageContextError, setWorkspacePageContextError] = useState<string | null>(null);
  const [growthContextJump, setGrowthContextJump] = useState<GrowthContextJumpRequest | null>(null);
