  async function probeLocalBackendHealth(probeTimeoutMs = 1800) {
    return await new Promise<HealthResponse>((resolve, reject) => {
      const timer = window.setTimeout(() => {
        reject(new Error('local-backend-health-timeout'));
      }, probeTimeoutMs);
      void getHealth()
        .then((response) => {
          window.clearTimeout(timer);
          resolve(response);
        })
        .catch((error) => {
          window.clearTimeout(timer);
          reject(error);
        });
    });
  }

  async function waitForLocalBackendReady(timeoutMs = 25000) {
    if (backendReadyRef.current) {
      return;
    }
    const startedAt = Date.now();
    let lastError: unknown = null;
    while (Date.now() - startedAt < timeoutMs) {
      try {
        const response = await probeLocalBackendHealth();
        setHealth(response);
        backendReadyRef.current = true;
        clearLocalServiceStartupBanner();
        return;
      } catch (error) {
        lastError = error;
        const detail = error instanceof Error ? error.message : String(error ?? '');
        console.warn(`[bootstrap] local backend probe failed: ${detail || 'unknown'}`);
        await new Promise((resolve) => window.setTimeout(resolve, 500));
      }
    }
    console.warn(
      `[bootstrap] local backend probe timed out after ${timeoutMs}ms, continuing startup`,
      lastError,
    );
  }

  useEffect(() => {
    if (!authState.authenticated) return undefined;
    let cancelled = false;
    let inFlight = false;
    const refreshHealth = async () => {
      if (inFlight || document.visibilityState !== 'visible') return;
      inFlight = true;
      try {
        const response = await probeLocalBackendHealth(1200);
        if (cancelled) return;
        setHealth(response);
        backendReadyRef.current = response.backend === 'online';
        clearLocalServiceStartupBanner();
      } catch {
        // Health refresh is only a status sync; startup/error flows handle user-facing failures.
      } finally {
        inFlight = false;
      }
    };
    const handleFocus = () => { void refreshHealth(); };
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') void refreshHealth();
    };
    const timer = window.setInterval(() => {
      void refreshHealth();
    }, 15000);
    window.addEventListener('focus', handleFocus);
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => {
      cancelled = true;
      window.clearInterval(timer);
      window.removeEventListener('focus', handleFocus);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [authState.authenticated]);

